def addition(a, b):
    # On additionne simplement les deux nombres reçus en paramètre
    return a + b

def nombre_de_lettres(mot):
    # len() renvoie le nombre de caractères d'une chaîne
    return len(mot)

def premiere_lettre(mot):
    # L'indice 0 correspond toujours au premier caractère d'une chaîne
    return mot[0]

def repetition(lettre, n):
    # La multiplication d'une chaîne par un entier la répète ce nombre de fois
    return n * lettre

def concatenation(mot1, mot2):
    # + concatène deux chaînes de caractères bout à bout
    return mot1 + mot2

def mot_a_trou(mot, lettre):
    resultat = ""
    # On parcourt le mot lettre par lettre
    for l in mot:
        if l != lettre:
            resultat += l
        else:
            # On remplace la lettre recherchée par un underscore
            resultat += "_"
    return resultat

def consonnes(mot):
    voyelles = "aeiouy"
    resultat = ""
    for lettre in mot:
        # On ne garde que les lettres qui ne sont PAS des voyelles
        if lettre not in voyelles:
            resultat += lettre
    return resultat

def contient_mot(phrase, mot):
    n_m = len(mot)
    n_p = len(phrase)
    # On teste toutes les positions de départ possibles dans phrase : la
    # dernière position valide est n_p - n_m (+1 car range s'arrête avant
    # sa borne haute)
    for i in range(n_p - n_m + 1):
        if phrase[i:i+n_m] == mot:
            return True
    return False

def verifier_majorite(age):
    # Une seule condition, avec if / else : deux issues possibles qui
    # s'excluent mutuellement (on ne peut pas être à la fois majeur et mineur)
    if age >= 18:
        return "Majeur"
    else:
        return "Mineur"

def signe(n):
    # Trois cas possibles, mutuellement exclusifs : if / elif / else
    # garantit qu'UNE SEULE des trois branches sera exécutée
    if n > 0:
        return "positif"
    elif n < 0:
        return "négatif"
    else:
        return "nul"

def reduction_cinema(age, etudiant, jour):
    reduction = 0

    # Chaque condition est vérifiée INDÉPENDAMMENT des autres (plusieurs
    # "if" séparés, pas de "elif") : plusieurs avantages peuvent s'appliquer
    # à la fois à la même personne, contrairement à un elif qui ne garderait
    # que le premier avantage trouvé et ignorerait les suivants
    if age < 12:
        reduction += 30

    if etudiant:
        reduction += 10

    if jour == "mardi":
        reduction += 10

    return reduction

def mention(moyenne):
    # Cinq cas mutuellement exclusifs : chaque elif ne teste que ce qui n'a
    # pas déjà été capturé par les conditions précédentes (on sait déjà que
    # moyenne >= 10 en arrivant au 2e elif, >= 12 au 3e, etc.)
    if moyenne < 10:
        return "Recalé"
    elif moyenne < 12:
        return "Passable"
    elif moyenne < 14:
        return "Assez bien"
    elif moyenne < 16:
        return "Bien"
    else:
        return "Très bien"

def est_bissextile(annee):
    # Cas 1 : pas divisible par 4 -> jamais bissextile, on s'arrête là
    if annee % 4 != 0:
        return False
    # Cas 2 : divisible par 4, ET pas par 100 -> bissextile (cas le plus courant)
    elif annee % 100 != 0:
        return True
    # Cas 3 : divisible par 100, ET pas par 400 -> exception, PAS bissextile
    elif annee % 400 != 0:
        return False
    # Cas 4 (dernier restant) : divisible par 400 -> bissextile
    else:
        return True

def calculette(a, b, operation):
    if operation == "+":
        return a + b
    elif operation == "-":
        return a - b
    elif operation == "*":
        return a * b
    elif operation == "/":
        # Cas particulier imbriqué DANS la branche "/" : on ne le teste que
        # quand l'opération demandée est bien une division
        if b == 0:
            return "Erreur : division par zéro"
        else:
            return a / b

def majeur(age):
    # True si age est supérieur ou égal à 18, False sinon
    return age >= 18

def est_pair(n):
    # Un nombre est pair si le reste de sa division par 2 vaut 0
    return n % 2 == 0

def reduction(age):
    # Loi de De Morgan : not (A or B) équivaut à (not A) and (not B)
    # Le contraire de "age < 18 ou age >= 60" est donc "age >= 18 et age < 60",
    # que l'on peut écrire en une seule comparaison : 18 <= age < 60
    # Il ne reste plus qu'à inverser ce résultat avec not
    return not (18 <= age < 60)

def somme_pairs(n):
    somme = 0
    # range(0, n, 2) parcourt 0, 2, 4, ... en s'arrêtant avant n
    for i in range(0, n, 2):
        somme += i
    return somme

def pgcd(a, b):
    if a == 0:
        return b
    if b == 0:
        return a

    # Tant que a et b sont différents, on soustrait le plus petit au plus
    # grand : le PGCD reste inchangé à chaque étape, et a finit par
    # rejoindre b (ou l'inverse)
    while a != b:
        if a > b:
            a = a - b
        else:
            b = b - a
    return a

def est_premier(n):
    # Par définition, aucun nombre inférieur à 2 n'est premier
    if n < 2:
        return False

    # On teste tous les diviseurs possibles de 2 à n-1 : si l'un d'eux
    # divise n exactement, n n'est pas premier
    for diviseur in range(2, n):
        if n % diviseur == 0:
            return False

    return True

def nombre_diviseurs(n):
    compteur = 0

    # On teste chaque nombre de 1 à n : s'il divise n sans reste, c'est
    # un diviseur
    for diviseur in range(1, n + 1):
        if n % diviseur == 0:
            compteur += 1

    return compteur

def est_palindrome(mot):
    n = len(mot)

    # On compare le caractère d'indice i (depuis le début) à celui
    # d'indice -1-i (depuis la fin) ; n//2 suffit car au-delà on
    # recomparerait les mêmes paires en sens inverse
    for i in range(n // 2):
        if mot[i] != mot[-1 - i]:
            return False

    return True

def minimum(liste):
    # On part du premier élément comme "meilleur candidat" pour le minimum
    mini = liste[0]
    # Puis on compare chaque élément suivant : si on trouve plus petit,
    # on met à jour mini
    for i in range(1, len(liste)):
        if liste[i] < mini:
            mini = liste[i]
    return mini

def indice_minimum(liste):
    # On mémorise l'INDICE du plus petit élément trouvé jusqu'ici, pas sa valeur
    imini = 0
    for i in range(1, len(liste)):
        # On compare à liste[imini] (la valeur du minimum actuel),
        # pas à une variable "mini" séparée
        if liste[i] < liste[imini]:
            imini = i
    return imini

def indices_zeros(liste):
    indices = []
    for i in range(len(liste)):
        # On vérifie la VALEUR à l'indice i avant de décider de l'ajouter
        if liste[i] == 0:
            indices.append(i)  # on stocke l'indice i, pas la valeur liste[i]
    return indices

def elements_negatifs(liste):
    negatifs = []
    # On parcourt directement les valeurs (pas besoin des indices ici)
    for x in liste:
        if x < 0:
            negatifs.append(x)
    return negatifs

def element_present(liste, element):
    # "in" teste directement l'appartenance d'une valeur à une liste
    return element in liste


# Autre façon de faire, sans utiliser "in" : on parcourt la liste élément
# par élément, et on renvoie True dès qu'on trouve une correspondance.
def element_present_sans_in(liste, element):
    for x in liste:
        if x == element:
            return True
    return False

def nombre_cles(dictionnaire):
    # len() sur un dictionnaire renvoie son nombre de clés
    return len(dictionnaire)

def carnet_de_notes(noms, notes):
    dictionnaire = {}
    # On associe chaque prénom (noms[i]) à la note de MÊME position (notes[i])
    for i in range(len(noms)):
        dictionnaire[noms[i]] = notes[i]
    return dictionnaire

def fusionner_emprunts(dict1, dict2):
    fusion = {}
    for cle, valeur in dict1.items():
        # list(valeur) fait une COPIE de la liste plutôt que de réutiliser
        # directement la même : sans ça, fusion[cle] pointerait vers exactement
        # le même objet liste que dict1[cle], et une modification future du
        # résultat modifierait aussi dict1 à son insu (effet de bord caché)
        fusion[cle] = list(valeur)
    for cle, valeur in dict2.items():
        if cle in fusion:
            fusion[cle] = fusion[cle] + valeur
        else:
            fusion[cle] = list(valeur)
    return fusion

def cle_presente(dictionnaire, cle):
    # "in" sur un dictionnaire teste la présence parmi les CLÉS (pas les valeurs)
    return cle in dictionnaire

def valeur_presente(dictionnaire, valeur):
    # .values() renvoie toutes les valeurs du dictionnaire, sans les clés
    return valeur in dictionnaire.values()


# Autre façon de faire, sans "in" : on parcourt les valeurs une par une
def valeur_presente_avec_boucle(dictionnaire, valeur):
    for v in dictionnaire.values():
        if v == valeur:
            return True
    return False

def compter_occurrences(liste):
    compteur = {}
    for element in liste:
        if element in compteur:
            compteur[element] += 1
        else:
            compteur[element] = 1
    return compteur

def regrouper_par_longueur(mots):
    groupes = {}
    for mot in mots:
        longueur = len(mot)
        if longueur in groupes:
            groupes[longueur].append(mot)
        else:
            groupes[longueur] = [mot]
    return groupes

def fusion(L1, L2):
    resultat = []
    i, j = 0, 0
    # Tant qu'il reste des éléments des DEUX côtés, on compare et on prend le plus petit
    while i < len(L1) and j < len(L2):
        if L1[i] <= L2[j]:
            resultat.append(L1[i])
            i += 1
        else:
            resultat.append(L2[j])
            j += 1
    # Il reste des éléments dans L1 (L2 est épuisée) : on les ajoute un par un
    while i < len(L1):
        resultat.append(L1[i])
        i += 1
    # Il reste des éléments dans L2 (L1 est épuisée) : on les ajoute un par un
    while j < len(L2):
        resultat.append(L2[j])
        j += 1
    return resultat

