def tri_fusion(L):
    # Cas de base : une liste de 0 ou 1 élément est déjà triée
    if len(L) <= 1:
        return L
    # On coupe la liste en deux moitiés...
    milieu = len(L) // 2
    # ...et on trie CHAQUE moitié récursivement (diviser pour régner)
    gauche = tri_fusion(L[:milieu])
    droite = tri_fusion(L[milieu:])
    # On fusionne ensuite les deux moitiés triées en une seule liste triée
    return fusion(gauche, droite)

def tri_rapide(L):
    # Cas de base : une liste de 0 ou 1 élément est déjà triée
    if len(L) <= 1:
        return L
    # On choisit le premier élément de L comme pivot
    pivot = L[0]
    inferieurs = []
    egaux = []
    superieurs = []
    # On répartit chaque élément de L selon sa comparaison au pivot
    for x in L:
        if x < pivot:
            inferieurs.append(x)
        elif x == pivot:
            egaux.append(x)
        else:
            superieurs.append(x)
    # On trie récursivement les deux listes extrêmes, puis on recolle le tout :
    # inférieurs triés + égaux (déjà à leur place, au milieu) + supérieurs triés
    return tri_rapide(inferieurs) + egaux + tri_rapide(superieurs)

