def est_connexe(graphe):
    # On choisit un nœud de départ arbitraire : le premier du dictionnaire
    depart = next(iter(graphe))
    # "visites" est un set (pas une liste) : on n'a besoin que de tester
    # l'appartenance, pas de conserver l'ordre de visite
    visites = {depart}
    file = [depart]
    while file:
        noeud = file.pop(0)
        for voisin in graphe[noeud]:
            if voisin not in visites:
                visites.add(voisin)
                file.append(voisin)
    # Le graphe est connexe si on a réussi à atteindre TOUS ses nœuds
    # depuis un seul point de départ
    return len(visites) == len(graphe)

def puissance(a, n):
    # Cas de base : n = 0, a**0 vaut toujours 1, quelle que soit la valeur de a
    if n == 0:
        return 1
    # Cas général : a**n = a * a**(n-1)
    # L'appel récursif se fait sur n - 1, qui se rapproche du cas de base (n = 0)
    # à chaque appel
    return a * puissance(a, n - 1)

def factorielle(n):
    # Cas de base : par convention, la factorielle de 0 vaut 1
    if n == 0:
        return 1
    # Cas général : n! = n * (n-1)!
    # L'appel récursif se fait sur n - 1, qui se rapproche du cas de base (n = 0)
    return n * factorielle(n - 1)

def somme_liste(liste):
    # Cas de base : une liste vide n'a rien à additionner, sa somme vaut 0
    if liste == []:
        return 0
    # Cas général : la somme de liste = son premier élément + la somme du reste
    # liste[1:] est une liste plus courte d'un élément : elle se rapproche du
    # cas de base (liste vide) à chaque appel récursif
    return liste[0] + somme_liste(liste[1:])

def pgcd(a, b):
    # Cas de base : quand b vaut 0, le pgcd est a (rappel : pgcd(a, 0) = a)
    if b == 0:
        return a
    # Cas général : pgcd(a, b) = pgcd(b, a % b)
    # a % b se rapproche de 0 à chaque appel, ce qui garantit d'atteindre
    # le cas de base au bout d'un nombre fini d'appels
    return pgcd(b, a % b)

def ajouter_lettres(mot, lettre, n):
    # Cas de base : n = 0, il ne reste plus aucune lettre à ajouter
    if n == 0:
        return mot
    # Cas général : on ajoute une occurrence de lettre à la fin de mot,
    # puis on appelle récursivement avec n - 1 (une lettre de moins à ajouter),
    # ce qui se rapproche du cas de base à chaque appel
    return ajouter_lettres(mot + lettre, lettre, n - 1)

def somme_chiffres(n):
    # Cas de base : n a un seul chiffre (n < 10), la somme de ses chiffres
    # est n lui-même
    if n < 10:
        return n
    # Cas général : n % 10 donne le dernier chiffre de n, et n // 10 donne
    # n privé de ce dernier chiffre (division entière)
    # n // 10 est un nombre plus petit : il se rapproche du cas de base
    # (un seul chiffre) à chaque appel
    return n % 10 + somme_chiffres(n // 10)

def fibonacci(n):
    # Cas de base : les deux premiers termes de la suite sont donnés
    # directement (0 et 1)
    if n <= 1:
        return n
    # Cas général : DEUX appels récursifs cette fois, sur n-1 et n-2, tous
    # les deux plus petits que n -> on se rapproche bien du cas de base,
    # mais par deux chemins différents à chaque étape
    return fibonacci(n - 1) + fibonacci(n - 2)

def aplatir(liste):
    # Cas de base : une liste vide n'a rien à aplatir
    if liste == []:
        return []
    tete = liste[0]
    reste = liste[1:]
    # isinstance(tete, list) teste si tete est elle-même une liste (donc à
    # aplatir aussi), ou une valeur simple (à garder telle quelle)
    if isinstance(tete, list):
        # tete est une liste imbriquée : on l'aplatit récursivement, puis on
        # aplatit le reste, et on concatène les deux résultats (tous les
        # deux déjà "à plat")
        return aplatir(tete) + aplatir(reste)
    else:
        # tete est une valeur simple : on la place dans une liste à un seul
        # élément, puis on aplatit le reste
        return [tete] + aplatir(reste)

def recherche_dichotomique(liste, cible, borne_inf=0, borne_sup=None):
    # borne_sup=None est une astuce classique pour donner une valeur par
    # défaut qui dépend de liste : on ne peut pas écrire directement
    # "borne_sup=len(liste)-1" dans l'en-tête (liste n'existe pas encore à
    # ce moment-là). Au premier appel (fait par l'utilisateur), on initialise
    # donc borne_sup ici, une seule fois.
    if borne_sup is None:
        borne_sup = len(liste) - 1

    # Cas de base : la portion à explorer est vide (borne_inf a dépassé
    # borne_sup) -> cible n'a été trouvée nulle part
    if borne_inf > borne_sup:
        return -1

    milieu = (borne_inf + borne_sup) // 2

    if liste[milieu] == cible:
        # Cas de base : on a trouvé cible exactement au milieu
        return milieu
    elif liste[milieu] < cible:
        # cible est plus grande : elle ne peut être que dans la moitié
        # DROITE (liste triée), on réduit donc la portion explorée en
        # excluant le milieu et tout ce qui est à sa gauche
        return recherche_dichotomique(liste, cible, milieu + 1, borne_sup)
    else:
        # cible est plus petite : elle ne peut être que dans la moitié
        # GAUCHE, on réduit la portion explorée en excluant le milieu et
        # tout ce qui est à sa droite
        return recherche_dichotomique(liste, cible, borne_inf, milieu - 1)

