from math import sqrt

def distance(fruit1, fruit2):
    poids1, diametre1 = fruit1
    poids2, diametre2 = fruit2
    return sqrt((poids1 - poids2) ** 2 + (diametre1 - diametre2) ** 2)


def plus_proches_voisins(fruit, echantillons, k):
    distances = []
    for poids, diametre, etiquette in echantillons:
        d = distance(fruit, [poids, diametre])
        distances.append((d, etiquette))
    resultat = []
    for _ in range(k):
        indice_min = 0
        for i in range(1, len(distances)):
            if distances[i][0] < distances[indice_min][0]:
                indice_min = i
        _, etiquette = distances.pop(indice_min)
        resultat.append(etiquette)
    return resultat


def classifier_fruit(fruit, echantillons, k):
    voisins = plus_proches_voisins(fruit, echantillons, k)
    # On compte le nombre d'occurrences de chaque étiquette parmi les voisins
    compteur = {}
    for etiquette in voisins:
        if etiquette in compteur:
            compteur[etiquette] += 1
        else:
            compteur[etiquette] = 1
    # On cherche l'étiquette dont le compteur est le plus élevé, en parcourant
    # les voisins DANS L'ORDRE (du plus proche au plus éloigné). Ainsi, en cas
    # d'égalité entre deux étiquettes, celle qui atteint la première ce score
    # maximal est celle du voisin le plus proche parmi les deux — exactement
    # la règle de départage demandée dans l'énoncé.
    meilleure_etiquette = None
    meilleur_compte = -1
    for etiquette in voisins:
        if compteur[etiquette] > meilleur_compte:
            meilleur_compte = compteur[etiquette]
            meilleure_etiquette = etiquette
    return meilleure_etiquette

