_cache_fibonacci_top_down = {}


def fibonacci_top_down_v1(n):
    if n in _cache_fibonacci_top_down:
        return _cache_fibonacci_top_down[n]

    if n <= 1:
        resultat = n
    else:
        resultat = fibonacci_top_down_v1(n - 1) + fibonacci_top_down_v1(n - 2)

    _cache_fibonacci_top_down[n] = resultat
    return resultat


# --- Version 2 (recommandée) : cache défini À L'INTÉRIEUR de la fonction ---
# Le cache n'a aucune utilité en dehors de cet appel précis à
# fibonacci_top_down : pas besoin de le laisser traîner comme variable
# globale. En le créant à l'intérieur (ici via une fonction auxiliaire
# imbriquée, qui y accède par fermeture), on évite de polluer l'espace de
# noms global, et tout risque d'oublier de le remettre à zéro entre deux
# appels qui n'ont rien à voir l'un avec l'autre.
def fibonacci_top_down(n):
    cache = {}

    def aux(k):
        if k in cache:
            return cache[k]
        if k <= 1:
            resultat = k
        else:
            resultat = aux(k - 1) + aux(k - 2)
        cache[k] = resultat
        return resultat

    return aux(n)

# --- Version 1 : cache défini EN DEHORS de la fonction (variable globale) ---
_cache_chemin_grille_top_down = {}


def chemin_grille_top_down_v1(m, n):
    if (m, n) in _cache_chemin_grille_top_down:
        return _cache_chemin_grille_top_down[(m, n)]

    if m == 1 or n == 1:
        resultat = 1
    else:
        resultat = chemin_grille_top_down_v1(m - 1, n) + chemin_grille_top_down_v1(m, n - 1)

    _cache_chemin_grille_top_down[(m, n)] = resultat
    return resultat


# --- Version 2 (recommandée) : cache défini À L'INTÉRIEUR de la fonction ---
# Comme pour Fibonacci, le cache ne sert à rien une fois l'appel terminé :
# le créer à l'intérieur (via une fonction auxiliaire imbriquée) évite de le
# laisser traîner inutilement en variable globale.
def chemin_grille_top_down(m, n):
    cache = {}

    def aux(i, j):
        if (i, j) in cache:
            return cache[(i, j)]
        if i == 0 or j == 0:
            resultat = 1
        else:
            resultat = aux(i - 1, j) + aux(i, j - 1)
        cache[(i, j)] = resultat
        return resultat

    return aux(m - 1, n - 1)

# --- Version 1 : cache défini EN DEHORS de la fonction (variable globale) ---
_cache_rendu_top_down = {}


def rendu_top_down_v1(montant, pieces):
    if montant == 0:
        return 0

    # Le cache est partagé par TOUS les appels à rendu_top_down_v1, y compris
    # ceux faits avec des pieces différentes : on inclut donc pieces
    # (converti en tuple, pour être utilisable comme clé de dictionnaire)
    # dans la clé, sinon deux appels avec des systèmes de pièces différents
    # mais le même montant se marcheraient dessus par erreur
    cle = (montant, tuple(pieces))
    if cle in _cache_rendu_top_down:
        return _cache_rendu_top_down[cle]

    # -1 sert de sentinelle "impossible", aussi bien pendant la récursion
    # qu'à la sortie de la fonction : pas besoin d'une valeur différente
    # (comme None) réservée à l'interne
    meilleur = -1
    for piece in pieces:
        if piece <= montant:
            sous_resultat = rendu_top_down_v1(montant - piece, pieces)
            if sous_resultat != -1:
                candidat = sous_resultat + 1
                if meilleur == -1 or candidat < meilleur:
                    meilleur = candidat

    _cache_rendu_top_down[cle] = meilleur
    return meilleur


# --- Version 2 (recommandée) : cache défini À L'INTÉRIEUR de la fonction ---
# Ici l'avantage est encore plus net que pour Fibonacci : comme pieces peut
# changer d'un appel à l'autre, un cache global doit obligatoirement inclure
# pieces dans sa clé pour rester correct (voir Version 1). Avec un cache créé
# à l'intérieur de la fonction, ce problème disparaît totalement : chaque
# appel à rendu_top_down travaille avec SON PROPRE cache, tout neuf, donc
# plus besoin d'y penser.
def rendu_top_down(montant, pieces):
    cache = {}

    def aux(reste):
        if reste == 0:
            return 0
        if reste in cache:
            return cache[reste]

        meilleur = None
        for piece in pieces:
            if piece <= reste:
                sous_resultat = aux(reste - piece)
                if sous_resultat is not None:
                    candidat = sous_resultat + 1
                    if meilleur is None or candidat < meilleur:
                        meilleur = candidat

        cache[reste] = meilleur
        return meilleur

    resultat = aux(montant)
    return resultat if resultat is not None else -1

def rendu_bottom_up(montant, pieces):
    INFINI = float('inf')
    # table[m] contiendra le nombre minimal de pièces pour rendre m
    table = [0] + [INFINI] * montant

    for m in range(1, montant + 1):
        for piece in pieces:
            if piece <= m and table[m - piece] + 1 < table[m]:
                # Utiliser cette pièce donne un résultat meilleur que ce
                # qu'on avait trouvé jusqu'ici pour ce montant m
                table[m] = table[m - piece] + 1

    # Si table[montant] est resté à l'infini, aucune combinaison de pièces
    # ne permet de l'atteindre exactement
    return table[montant] if table[montant] != INFINI else -1

